module johnson_counter(clk, reset, q);

    input  clk;  
    input  reset;  
    output  [3:0] q;  
  wire _tap_clk = clk & {1{1'b1}};

    reg    [3:0] q; 
    initial q = 0;

    always @(posedge clk)
          begin
            if (reset) 
                q <= 0;
            else
                q <= {q[2:0], ~q[3]};
          end  

endmodule
